export const createTask = async (args: { description: string }) => {
  const task = await prisma.task.create({
    data: {
      description: args.description,
    },
  })
  return task
}

export const createLabel = async (args: { name: string }) => {
  const label = await prisma.label.create({
    data: {
      name: args.name,
    },
  })
  return label
}

export const addLabelToTask = async (args: { taskId: number; labelId: number }) => {
  const task = await prisma.task.update({
    where: {
      id: args.taskId,
    },
    data: {
      labels: {
        connect: {
          id: args.labelId,
        },
      },
    },
    include: {
      labels: true,
    },
  })
  return task
}

